/**
 * utils/recipeLibrary.ts — Built-in Recipe Library
 *
 * A large catalogue of basic, everyday recipes with full data:
 * ingredients, calories, macros (protein/carbs/fat), estimated cost
 * per serving, cook time, equipment tier, dietary tags, and a tip.
 *
 * Powers:
 *   • The browsable Recipe Library in the Recipes & Resources tab
 *   • The smart Week-Plan generator (calorie / protein / budget aware)
 *
 * Costs and calories are stored PER SERVING (already divided down),
 * so the generator can sum them directly without unit math.
 */

import type { EquipmentTier, MealTypeKey } from './mealData'

export interface LibraryRecipe {
  id:          string
  name:        string
  mealType:    MealTypeKey          // breakfast | lunch | dinner
  categories:  string[]             // subset of RECIPE_CATEGORIES (browse filter)
  equipment:   EquipmentTier[]      // tiers that can make it
  cookMinutes: number
  cost:        number               // USD per serving
  calories:    number               // kcal per serving
  protein:     number               // g per serving
  carbs:       number               // g per serving
  fat:         number               // g per serving
  ingredients: string[]
  dietaryTags: string[]
  tips:        string
}

/* Shorthands for equipment combos to keep the dataset compact */
