/* ════════════════════════════════════════════════════════════════
   DERIVED INDEXES & HELPERS
   ════════════════════════════════════════════════════════════════ */

/** Recipes grouped by meal type (for the generator pools). */
export const RECIPES_BY_MEAL: Record<MealTypeKey, LibraryRecipe[]> = {
  breakfast: RECIPE_LIBRARY.filter(r => r.mealType === 'breakfast'),
  lunch:     RECIPE_LIBRARY.filter(r => r.mealType === 'lunch'),
  dinner:    RECIPE_LIBRARY.filter(r => r.mealType === 'dinner'),
}

/** Count of recipes that list a given category (for badge display). */
export function recipeCountForCategory(category: string): number {
  if (category === 'All') return RECIPE_LIBRARY.length
  return RECIPE_LIBRARY.filter(r => r.categories.includes(category)).length
}

/**
 * Filter the library by category, free-text query, equipment, dietary tags,
 * disliked ingredients, and hidden recipe IDs. All filters are AND-combined.
 */
export function filterLibrary(opts: {
  category?:  string
  query?:     string
  equipment?: EquipmentTier[]
  dietary?:   string[]
  disliked?:  string[]
  hiddenIds?: Set<string>
}): LibraryRecipe[] {
  const { category = 'All', query = '', equipment = [], dietary = [], disliked = [], hiddenIds } = opts
  const q     = query.trim().toLowerCase()
  const lower = disliked.map(d => d.toLowerCase())

  return RECIPE_LIBRARY.filter(r => {
    if (hiddenIds && hiddenIds.has(r.id)) return false
    if (category !== 'All' && !r.categories.includes(category)) return false
    if (q) {
      const hay = `${r.name} ${r.ingredients.join(' ')} ${r.categories.join(' ')}`.toLowerCase()
      if (!hay.includes(q)) return false
    }
    if (equipment.length && !equipment.some(e => r.equipment.includes(e))) return false
    if (dietary.length  && !dietary.every(tag => r.dietaryTags.includes(tag))) return false
    if (lower.length) {
      const hasDisliked = r.ingredients.some(ing => lower.some(d => ing.toLowerCase().includes(d)))
      if (hasDisliked) return false
    }
    return true
  })
}
